    emit_u(0x3f060a92u);          /* pi/6: cos = sqrt(3)/2 */
    emit_u(0x3f490fdbu);          /* pi/4: cos = sqrt(2)/2 */
    emit_u(0x3f860a92u);          /* pi/3: cos = 0.5 */
    emit_u(0x3fc90fdbu);          /* pi/2: cos = 0 */
    emit_u(0x3fa8279bu);          /* 2pi/3 */
    emit_u(0x3fb6cbe4u);          /* 3pi/4 */
    emit_u(0x3fc3b346u);          /* 5pi/6 */
    emit_u(0x40490fdbu);          /* pi: cos = -1 */
    emit_u(0x4096cbe4u);          /* 3pi/2: cos = 0 */
    emit_u(0x40c90fdbu);          /* 2pi: cos = 1 */
    emit_u(0xbf490fdbu);          /* -pi/4 */
    emit_u(0xbfc90fdbu);          /* -pi/2 */
    emit_u(0xc0490fdbu);          /* -pi */
    emit_u(0xc0c90fdbu);          /* -2pi */

    /* --- Section 7: Argument reduction stress (8) --- */
    emit_u(0x4b400000u);          /* 12582912.0 = 4*2^21, near pi multiple */
    emit_u(0x4dc90fdbu);          /* ~100*pi as float */
    emit_u(0x501b74eeu);          /* ~1000*pi as float */
    emit(1.0e7f);
    emit(1.0e10f);
    emit(-1.0e7f);
    emit(-1.0e10f);
    emit_u(0x4b000000u);          /* 2^23: mantissa precision boundary */

    /* --- Section 8: ULP neighbors of key trig boundaries (15) --- */
    /* triplet around pi/2: 0x3fc90fdb */
    emit_u(0x3fc90fdau);          /* one ULP below pi/2 */
    emit_u(0x3fc90fdbu);          /* pi/2 */
    emit_u(0x3fc90fdcu);          /* one ULP above pi/2 */
    /* triplet around pi: 0x40490fdb */
    emit_u(0x40490fdau);          /* one ULP below pi */
    emit_u(0x40490fdbu);          /* pi */
    emit_u(0x40490fdcu);          /* one ULP above pi */
    /* triplet around 3pi/2: 0x4096cbe4 */
    emit_u(0x4096cbe3u);          /* one ULP below 3pi/2 */
    emit_u(0x4096cbe4u);          /* 3pi/2 */
    emit_u(0x4096cbe5u);          /* one ULP above 3pi/2 */
    /* triplet around 2pi: 0x40c90fdb */
    emit_u(0x40c90fdau);          /* one ULP below 2pi */
    emit_u(0x40c90fdbu);          /* 2pi */
    emit_u(0x40c90fdcu);          /* one ULP above 2pi */
    /* triplet around -pi/2: 0xbfc90fdb */
    emit_u(0xbfc90fdau);          /* one ULP toward zero from -pi/2 */
    emit_u(0xbfc90fdbu);          /* -pi/2 */
    emit_u(0xbfc90fdcu);          /* one ULP away from zero from -pi/2 */

    /* --- Section 9: Small-argument fast-path boundaries (8) --- */
    emit_u(0x39800000u);          /* 2^-12: lower bound of linear region */
    emit_u(0xb9800000u);          /* -2^-12 */
    emit_u(0x3c000000u);          /* 2^-7 */
    emit_u(0xbc000000u);          /* -2^-7 */
    emit_u(0x3a800000u);          /* 2^-10 */
    emit_u(0xba800000u);          /* -2^-10 */
    emit_u(0x33800000u);          /* 2^-24: one-ULP magnitude for float */
    emit_u(0xb3800000u);          /* -2^-24 */

