    /* triplet around pi/8: 0x3ec90fdb */
    emit_u(0x3ec90fdau);          /* one ULP below pi/8 */
    emit_u(0x3ec90fdbu);          /* pi/8 */
    emit_u(0x3ec90fdcu);          /* one ULP above pi/8 */
    /* triplet around pi/4: 0x3f490fdb */
    emit_u(0x3f490fdau);          /* one ULP below pi/4 */
    emit_u(0x3f490fdbu);          /* pi/4 */
    emit_u(0x3f490fdcu);          /* one ULP above pi/4 */
    /* 3pi/8 and -3pi/8: exercises cos-path reconstruction */
    emit_u(0x3f96cbe4u);          /* 3pi/8 */
    emit_u(0xbf96cbe4u);          /* -3pi/8 */
    /* k*pi for k = 3, 4, 5 (cos ~ +-1, cancellation stress) */
    emit_u(0x40db4510u);          /* 3*pi */
    emit_u(0x41490fdbu);          /* 4*pi */
    emit_u(0x419cb27fu);          /* 5*pi */
    /* odd half-multiples: 5pi/2, 7pi/2, -5pi/2 (cos = 0 after reduction) */
    emit_u(0x40f6cbe4u);          /* 5pi/2 */
    emit_u(0x4116cbe4u);          /* 7pi/2 */
    emit_u(0xc0f6cbe4u);          /* -5pi/2 */
    /* non-pi normals */
    emit(3.0f);
    emit(-3.0f);
    /* large int multiples of pi (catastrophic reduction) */
    emit_u(0x461c9c3au);          /* 10*pi as float */
    emit_u(0x48c90fdbu);          /* 100000*pi approximation */
    /* scaled pi/2 patterns at 2^23 magnitude (Payne-Hanek stress) */
    emit_u(0x4b490fdbu);          /* 2^23 * (pi/2 normalized) */
    emit_u(0x4bc90fdbu);          /* 2^24 * pi/2 */
    /* additional hard-rounded float */
    emit_u(0x4a7d6857u);          /* known hard cosf reduction case */
    emit_u(0x49742410u);          /* another large-arg hard reduction: ~1e6 */
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 4*pi] and [-4*pi, 0] in 200 steps each */
static void test_sweep(void)
{
    float hi = 4.0f * 3.14159265358979323846f;
    int nsteps = 200;
    float step = hi / (float)nsteps;

    /* [0, 4*pi] */
    for (int i = 0; i <= nsteps; i++)
        emit((float)i * step);

    /* [-4*pi, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (float)i * step);
}

/* 8. Sample [0, pi/4] every 4194304 ULP (~250 cases) */
static void test_exhaustive_small(void)
{
    uint32_t end = 0x3f490fdbu; /* pi/4 */
    for (uint32_t b = 0; b <= end; b += 4194304)
        emit_u(b);
}
#endif

/* ------------------------------------------------------------------ */

#ifdef EN_PERF
/*
 * perf(x) -- exercise the hot kernel path N times and print the result.
 *
 * Critical path for cosf():
 *   __gf_fpreduct  (argument reduction)
 *   -> __gf_exmul  (extended-precision multiply)
 *   -> __gf_sigmax(__gf_fpcoscof, degree 5)  (polynomial kernel)
 *   -> __gf_exmul  (scale result)
 *
 * This path is taken when the reduced quadrant index q satisfies
 * (q-1)&2 == 0, i.e. q == 1 or q == 2.  x = 1.0 falls in quadrant 0.
 */
static void perf(float x)
{
    volatile float acc = 0.0f;
    startPFM;
    for (int i = 0; i < 100; i++)
        acc += cosf(x+i);
    stopPFM;
    readResult();
    printf("perf %08lx: %08lx\n",
           (unsigned long)f2u(x),
           (unsigned long)f2u((float)acc));
}
#endif /* EN_PERF */

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    perf(1.0f); /* quadrant 0: hits cos-polynomial kernel path */
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

