/*
 * tanh() test harness — prints (input_hex, output_hex) pairs.
 *
 * Build two versions:
 *   1. Linked with optimized Andes assembly tanh  (test_tanh_opt.elf)
 *   2. Linked with toolchain's default tanh        (test_tanh_ref.elf)
 * Run both, diff the output to find discrepancies.
 */

#include <math.h>
#include <stdint.h>
#include <stdio.h>
#include <float.h>

#ifdef EN_PERF
#define PF_COUNTER
#include "nds_pfcounter.h"
#endif

static inline uint64_t d2u(double d)
{
    union { double d; uint64_t u; } x;
    x.d = d;
    return x.u;
}

static inline double u2d(uint64_t u)
{
    union { double d; uint64_t u; } x;
    x.u = u;
    return x.d;
}

static volatile double g_acc;

static void emit(double x)
{
#ifdef EN_PERF
    volatile double vx = x;  /* prevent constant-folding of literal arguments */
    g_acc += tanh(vx);
#else
    double r = tanh(x);
    printf("%016llx %016llx\n", (unsigned long long)d2u(x), (unsigned long long)d2u(r));
#endif
}

static void emit_u(uint64_t bits)
{
    emit(u2d(bits));
}

/* ------------------------------------------------------------------ */
/* test_representative_100: 100 representative inputs for tanh()      */
/* ------------------------------------------------------------------ */

static void test_representative_100(void)
{
    /* --- Section 1: Special IEEE 754 values (7) --- */
    emit(0.0);
    emit(-0.0);
    emit_u(0x7ff8000000000000ULL);  /* qNaN */
    emit_u(0x7ff0000000000001ULL);  /* sNaN */
    emit_u(0xfff8000000000000ULL);  /* -qNaN */
    emit_u(0x7ff0000000000000ULL);  /* +Inf -> tanh = +1.0 */
    emit_u(0xfff0000000000000ULL);  /* -Inf -> tanh = -1.0 */

    /* --- Section 2: Subnormal (denormal) values (6) --- */
    emit_u(0x0000000000000001ULL);  /* min positive subnormal: 2^-1074 */
    emit_u(0x8000000000000001ULL);  /* min negative subnormal */
    emit_u(0x0008000000000000ULL);  /* mid positive subnormal */
    emit_u(0x8008000000000000ULL);  /* mid negative subnormal */
    emit_u(0x000fffffffffffffULL);  /* max subnormal: just below DBL_MIN */
    emit_u(0x800fffffffffffffULL);  /* max negative subnormal */

    /* --- Section 3: Normal boundary values (6) --- */
    emit_u(0x0010000000000000ULL);  /* DBL_MIN = 2^-1022, smallest normal */
    emit_u(0x8010000000000000ULL);  /* -DBL_MIN */
    emit_u(0x0010000000000001ULL);  /* one ULP above DBL_MIN */
    emit_u(0x7fefffffffffffffULL);  /* DBL_MAX: tanh = 1.0 */
    emit_u(0xffefffffffffffffULL);  /* -DBL_MAX: tanh = -1.0 */
    emit_u(0x7feffffffffffff0ULL);  /* a few ULPs below DBL_MAX */

    /* --- Section 4: Near 1.0 ULP density (8) --- */
    emit_u(0x3fefffffffffffffULL);  /* one ULP below 1.0 */
    emit(1.0);
    emit_u(0x3ff0000000000001ULL);  /* one ULP above 1.0 */
    emit_u(0x3fefffffffffffc0ULL);  /* several ULPs below 1.0 */
    emit_u(0x3ff0000000000010ULL);  /* several ULPs above 1.0 */
    emit(-1.0);
    emit_u(0xbfefffffffffffffULL);  /* one ULP toward zero from -1.0 */
    emit_u(0xbff0000000000001ULL);  /* one ULP away from zero from -1.0 */

    /* --- Section 5: Exponent switching points (6) --- */
    emit_u(0x3fe0000000000000ULL);  /* 0.5 */
    emit_u(0x3fdffffffffffffeULL);  /* one ULP below 0.5 */
    emit_u(0x3fe0000000000001ULL);  /* one ULP above 0.5 */
    emit_u(0x4000000000000000ULL);  /* 2.0 */
    emit_u(0x3fffffffffffffffULL);  /* one ULP below 2.0 */
    emit_u(0x4000000000000001ULL);  /* one ULP above 2.0 */

    /* --- Section 6: Mathematical constants and known values (18) --- */
    emit_u(0x3fe62e42fefa39efULL);  /* ln2 ~ 0.6931: tanh(ln2) = 3/5 = 0.6 */
    emit(0.1);
    emit(-0.1);
    emit(0.25);
    emit(-0.25);
    emit(0.5);
    emit(-0.5);
    emit(0.75);
    emit(-0.75);
    emit(1.5);
    emit(-1.5);
    emit(3.0);
    emit(-3.0);
    emit(1.25);
    emit(-1.25);
    emit(2.0);
    emit(-2.0);
    emit(1.0);

    /* --- Section 7: Saturation region (8) --- */
    /* tanh saturates toward +-1 for |x| > ~4; all results are 1 - epsilon */
    emit(4.0);
    emit(-4.0);
    emit(5.0);
    emit(-5.0);
    emit(10.0);
    emit(-10.0);
    emit(20.0);
    emit(-20.0);

    /* --- Section 8: Small-argument fast-path boundaries (8) --- */
    /* For small |x|, tanh(x) ~ x; test at power-of-2 thresholds */
    emit_u(0x3fb0000000000000ULL);  /* 2^-4 = 0.0625 */
    emit_u(0xbfb0000000000000ULL);  /* -2^-4 */
    emit_u(0x3f80000000000000ULL);  /* 2^-7 */
    emit_u(0xbf80000000000000ULL);  /* -2^-7 */
    emit_u(0x3e50000000000000ULL);  /* 2^-26: well into tanh(x)~x territory */
    emit_u(0xbe50000000000000ULL);  /* -2^-26 */
    emit_u(0x3c90000000000000ULL);  /* 2^-54: below double precision epsilon */
    emit_u(0xbc90000000000000ULL);  /* -2^-54 */

    /* --- Section 9: ULP neighbors of ln2 and 2*ln2 (7) --- */
    emit_u(0x3fe62e42fefa39eeULL);  /* one ULP below ln2 */
    emit_u(0x3fe62e42fefa39f0ULL);  /* one ULP above ln2 */
    emit_u(0x3ff62e42fefa39efULL);  /* 2*ln2 ~ 1.3863 */
    emit_u(0x3ff62e42fefa39eeULL);  /* one ULP below 2*ln2 */
    emit_u(0x3ff62e42fefa39f0ULL);  /* one ULP above 2*ln2 */
    emit_u(0x3fe0000000000002ULL);  /* two ULPs above 0.5 */
    emit_u(0x3fdffffffffffffdULL);  /* two ULPs below 0.5 */

    /* --- Section 10: Saturation onset and large values (19) --- */
    /* Values just below and above tanh saturation onset ~19.06 (tanh = 1 - 2^-55) */
    emit_u(0x4032f5aa98ca0eb5ULL);  /* ~19.06, near 1-ulp saturation point double */
    emit_u(0x4032f5aa98ca0eb4ULL);  /* one ULP below saturation onset */
    emit_u(0x4032f5aa98ca0eb6ULL);  /* one ULP above saturation onset */
    emit(50.0);
    emit(-50.0);
    emit(100.0);
    emit(-100.0);
    emit(500.0);
    emit(-500.0);
    emit(709.0);   /* near exp overflow threshold, tanh = 1.0 */
    emit(-709.0);
    /* tanh(x)=0.5 at x = atanh(0.5) ~ 0.5493 */
    emit_u(0x3fe1939b4cda8d6bULL);  /* atanh(0.5) ~ 0.54930614 */
    emit_u(0xbfe1939b4cda8d6bULL);  /* -atanh(0.5) */
    /* tanh(x)=0.9 at x = atanh(0.9) ~ 1.4722 */
    emit_u(0x3ff78b56362cef38ULL);  /* atanh(0.9) ~ 1.4722 */
    emit_u(0xbff78b56362cef38ULL);  /* -atanh(0.9) */
    /* tanh(x)=0.99 at x = atanh(0.99) ~ 2.6467 */
    emit_u(0x4005268ef3730b55ULL);  /* atanh(0.99) ~ 2.6467 */
    emit_u(0xc005268ef3730b55ULL);  /* -atanh(0.99) */
    emit(1.75);
    emit(-1.75);
    emit(2.5);
    emit(-2.5);
}

/* ------------------------------------------------------------------ */

#ifndef EN_PERF
/* 7. Sweep [0, 10] in 100 steps and [-10, 0] in 100 steps */
static void test_sweep(void)
{
    double hi = 10.0;
    int nsteps = 100;
    double step = hi / (double)nsteps;

    /* [0, 10] */
    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);

    /* [-10, 0] */
    for (int i = 0; i <= nsteps; i++)
        emit(-hi + (double)i * step);
}

/* 8. Sample [0, 10] every ~0.05 (200 points) */
static void test_exhaustive_small(void)
{
    double hi = 10.0;
    int nsteps = 200;
    double step = hi / (double)nsteps;

    for (int i = 0; i <= nsteps; i++)
        emit((double)i * step);
}
#endif

/* ------------------------------------------------------------------ */

int main(void)
{
#ifdef EN_PERF
    startPFM;
    test_representative_100();
    stopPFM;
    readResult();
    printf("perf acc: %016llx\n", (unsigned long long)d2u((double)g_acc));
#else
    test_representative_100();
    test_sweep();
    test_exhaustive_small();
#endif
    return 0;
}

